import {
  BindingMetricEvent,
  SessionBindingMetricsService,
} from '../../services/security/SessionBindingMetricsService';

// Mock Application Insights
jest.mock('applicationinsights', () => ({
  defaultClient: {
    trackEvent: jest.fn(),
  },
}));

// Mock logger
jest.mock('../../utils/logger', () => ({
  logger: {
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn(),
  },
}));

describe('SessionBindingMetricsService', () => {
  let service: SessionBindingMetricsService;

  beforeEach(() => {
    // Get fresh instance and reset for each test
    service = SessionBindingMetricsService.getInstance();
    service.reset();
  });

  describe('Singleton Pattern', () => {
    it('should return same instance on multiple calls', () => {
      const instance1 = SessionBindingMetricsService.getInstance();
      const instance2 = SessionBindingMetricsService.getInstance();
      expect(instance1).toBe(instance2);
    });
  });

  describe('recordMismatch()', () => {
    it('should increment mismatch counter', () => {
      const event: BindingMetricEvent = {
        userId: 'user-123',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      service.recordMismatch(event);

      expect(service.getEventCounts().mismatchCount).toBe(1);
    });

    it('should track mismatch reasons (IP change)', () => {
      const event: BindingMetricEvent = {
        userId: 'user-123',
        success: false,
        mismatches: { ip: true },
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      service.recordMismatch(event);

      const reasons = service.getMismatchByReason();
      expect(reasons.ip).toBe(1);
      expect(reasons.userAgent).toBe(0);
      expect(reasons.deviceFingerprint).toBe(0);
    });

    it('should track mismatch reasons (User-Agent change)', () => {
      const event: BindingMetricEvent = {
        userId: 'user-123',
        success: false,
        mismatches: { userAgent: true },
        path: '/api/v2/activities',
        enforced: true,
        timestamp: new Date(),
      };

      service.recordMismatch(event);

      const reasons = service.getMismatchByReason();
      expect(reasons.userAgent).toBe(1);
    });

    it('should track multiple mismatch reasons', () => {
      const event: BindingMetricEvent = {
        userId: 'user-123',
        success: false,
        mismatches: { ip: true, userAgent: true },
        path: '/api/v2/ships',
        enforced: true,
        timestamp: new Date(),
      };

      service.recordMismatch(event);

      const reasons = service.getMismatchByReason();
      expect(reasons.ip).toBe(1);
      expect(reasons.userAgent).toBe(1);
    });

    it('should not throw on error (fail-soft)', () => {
      const event: BindingMetricEvent = {
        userId: 'user-123',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      // Should not throw even if Application Insights fails
      expect(() => {
        service.recordMismatch(event);
      }).not.toThrow();
    });
  });

  describe('recordSuccess()', () => {
    it('should increment success counter', () => {
      const event = {
        userId: 'user-456',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      service.recordSuccess(event);

      expect(service.getEventCounts().successCount).toBe(1);
    });

    it('should not throw on error (fail-soft)', () => {
      const event = {
        userId: 'user-456',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      expect(() => {
        service.recordSuccess(event);
      }).not.toThrow();
    });
  });

  describe('getMismatchRate()', () => {
    it('should return 0% for empty state', () => {
      const rate = service.getMismatchRate();
      expect(rate).toBe(0);
    });

    it('should calculate correct rate: 50%', () => {
      const event1: BindingMetricEvent = {
        userId: 'user-123',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };
      const event2 = {
        userId: 'user-456',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      service.recordMismatch(event1);
      service.recordSuccess(event2);

      const rate = service.getMismatchRate();
      expect(rate).toBe(50);
    });

    it('should calculate correct rate: 33.33%', () => {
      // 1 mismatch, 2 successes = 33.33%
      service.recordMismatch({
        userId: 'user-123',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordSuccess({
        userId: 'user-456',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordSuccess({
        userId: 'user-789',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      const rate = service.getMismatchRate();
      expect(rate).toBe(33.33);
    });

    it('should calculate correct rate: 2% (40 mismatches, 1960 successes)', () => {
      for (let i = 0; i < 40; i++) {
        service.recordMismatch({
          userId: `user-mismatch-${i}`,
          success: false,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      for (let i = 0; i < 1960; i++) {
        service.recordSuccess({
          userId: `user-success-${i}`,
          success: true,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      const rate = service.getMismatchRate();
      expect(rate).toBe(2);
    });

    it('should handle rounding accurately', () => {
      // 1/3 = 33.333... should round to 33.33
      service.recordMismatch({
        userId: 'user-1',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordSuccess({
        userId: 'user-2',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordSuccess({
        userId: 'user-3',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      const rate = service.getMismatchRate();
      // 1/3 * 100 = 33.333...
      // Rounded to 2 decimals = 33.33
      expect(rate).toBe(33.33);
    });
  });

  describe('shouldAlertThreshold()', () => {
    it('should return false when rate < 5%', () => {
      for (let i = 0; i < 490; i++) {
        service.recordSuccess({
          userId: `user-${i}`,
          success: true,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }
      service.recordMismatch({
        userId: 'user-alert',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      // Rate = 1/491 = 0.20% (below 5%)
      expect(service.shouldAlertThreshold()).toBe(false);
    });

    it('should return true when rate > 5%', () => {
      for (let i = 0; i < 50; i++) {
        service.recordMismatch({
          userId: `user-mismatch-${i}`,
          success: false,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }
      for (let i = 0; i < 950; i++) {
        service.recordSuccess({
          userId: `user-success-${i}`,
          success: true,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      // Rate = 50/1000 = 5%
      expect(service.shouldAlertThreshold()).toBe(false); // Exactly 5% should not alert

      // Add one more mismatch to cross threshold
      service.recordMismatch({
        userId: 'user-mismatch-51',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      // Rate = 51/1001 = 5.09% (above 5%)
      expect(service.shouldAlertThreshold()).toBe(true);
    });
  });

  describe('getEventCounts()', () => {
    it('should return correct counts', () => {
      service.recordMismatch({
        userId: 'user-1',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordSuccess({
        userId: 'user-2',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordSuccess({
        userId: 'user-3',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      const counts = service.getEventCounts();
      expect(counts.mismatchCount).toBe(1);
      expect(counts.successCount).toBe(2);
      expect(counts.total).toBe(3);
    });
  });

  describe('getMismatchByReason()', () => {
    it('should track multiple reasons separately', () => {
      service.recordMismatch({
        userId: 'user-1',
        success: false,
        mismatches: { ip: true },
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordMismatch({
        userId: 'user-2',
        success: false,
        mismatches: { userAgent: true },
        path: '/api/v2/activities',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordMismatch({
        userId: 'user-3',
        success: false,
        mismatches: { ip: true, deviceFingerprint: true },
        path: '/api/v2/ships',
        enforced: true,
        timestamp: new Date(),
      });

      const reasons = service.getMismatchByReason();
      expect(reasons.ip).toBe(2); // 2 IP mismatches
      expect(reasons.userAgent).toBe(1); // 1 UA mismatch
      expect(reasons.deviceFingerprint).toBe(1); // 1 device mismatch
    });
  });

  describe('reset()', () => {
    it('should clear all counters', () => {
      service.recordMismatch({
        userId: 'user-1',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });
      service.recordSuccess({
        userId: 'user-2',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      expect(service.getEventCounts().total).toBe(2);

      service.reset();

      expect(service.getEventCounts().mismatchCount).toBe(0);
      expect(service.getEventCounts().successCount).toBe(0);
      expect(service.getMismatchRate()).toBe(0);
    });
  });

  describe('Concurrency & Performance', () => {
    it('should handle 1000 concurrent events safely', () => {
      const promises: Promise<void>[] = [];

      for (let i = 0; i < 1000; i++) {
        const isSuccess = i % 2 === 0;

        if (isSuccess) {
          promises.push(
            Promise.resolve().then(() => {
              service.recordSuccess({
                userId: `user-${i}`,
                success: true,
                path: '/api/v2/fleets',
                enforced: true,
                timestamp: new Date(),
              });
            })
          );
        } else {
          promises.push(
            Promise.resolve().then(() => {
              service.recordMismatch({
                userId: `user-${i}`,
                success: false,
                path: '/api/v2/fleets',
                enforced: true,
                timestamp: new Date(),
              });
            })
          );
        }
      }

      // Wait for all to complete
      return Promise.all(promises).then(() => {
        // Verify counts are correct (500 mismatch, 500 success)
        const counts = service.getEventCounts();
        expect(counts.total).toBe(1000);
        expect(counts.mismatchCount).toBe(500);
        expect(counts.successCount).toBe(500);
        expect(service.getMismatchRate()).toBe(50);
      });
    });

    it('should complete 100 rapid-fire events in < 10ms', () => {
      const startTime = Date.now();

      for (let i = 0; i < 100; i++) {
        if (i % 3 === 0) {
          service.recordMismatch({
            userId: `user-${i}`,
            success: false,
            path: '/api/v2/fleets',
            enforced: true,
            timestamp: new Date(),
          });
        } else {
          service.recordSuccess({
            userId: `user-${i}`,
            success: true,
            path: '/api/v2/fleets',
            enforced: true,
            timestamp: new Date(),
          });
        }
      }

      const elapsed = Date.now() - startTime;
      expect(elapsed).toBeLessThan(10); // Should be much faster than 10ms
    });
  });

  describe('Error Handling', () => {
    it('should not throw when Application Insights is unavailable', () => {
      const event: BindingMetricEvent = {
        userId: 'user-123',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      // recordMismatch should never throw, even in edge cases
      expect(() => {
        service.recordMismatch(event);
      }).not.toThrow();
    });

    it('should not throw when recording success', () => {
      const event = {
        userId: 'user-456',
        success: true,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      };

      expect(() => {
        service.recordSuccess(event);
      }).not.toThrow();
    });
  });

  describe('Edge Cases', () => {
    it('should handle anonymous user ID', () => {
      service.recordMismatch({
        userId: 'anonymous',
        success: false,
        path: '/api/v2/fleets',
        enforced: false,
        timestamp: new Date(),
      });

      expect(service.getEventCounts().mismatchCount).toBe(1);
    });

    it('should handle empty mismatch reasons', () => {
      service.recordMismatch({
        userId: 'user-123',
        success: false,
        mismatches: {},
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      const reasons = service.getMismatchByReason();
      expect(reasons.ip).toBe(0);
      expect(reasons.userAgent).toBe(0);
      expect(reasons.deviceFingerprint).toBe(0);
    });

    it('should handle undefined mismatch reasons', () => {
      service.recordMismatch({
        userId: 'user-123',
        success: false,
        path: '/api/v2/fleets',
        enforced: true,
        timestamp: new Date(),
      });

      const reasons = service.getMismatchByReason();
      expect(reasons.ip).toBe(0);
    });

    it('should calculate rate correctly with very large numbers', () => {
      // 100K successes, 1K mismatches = 1% rate
      for (let i = 0; i < 100000; i++) {
        service.recordSuccess({
          userId: `user-success-${i}`,
          success: true,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      for (let i = 0; i < 1000; i++) {
        service.recordMismatch({
          userId: `user-mismatch-${i}`,
          success: false,
          path: '/api/v2/fleets',
          enforced: true,
          timestamp: new Date(),
        });
      }

      const rate = service.getMismatchRate();
      expect(rate).toBe(0.99); // 1K / 101K = 0.99%
    });
  });
});
